import{_ as i,C as n,o as s,c as l,a4 as t,j as r,a,G as h}from"./chunks/framework.CZ62Rgnh.js";const f=JSON.parse('{"title":"Integration Paths","description":"","frontmatter":{},"headers":[],"relativePath":"overview/integration-paths.md","filePath":"overview/integration-paths.md"}'),d={name:"overview/integration-paths.md"},p={id:"path-3-kube-bind",tabindex:"-1"};function c(u,e,m,v,g,b){const o=n("Badge");return s(),l("div",null,[e[3]||(e[3]=t('<h1 id="integration-paths" tabindex="-1">Integration Paths <a class="header-anchor" href="#integration-paths" aria-label="Permalink to &quot;Integration Paths&quot;">​</a></h1><p>There are two ways to bring a service into the Platform Mesh today. The right choice depends on what you have and how much control you need. Both paths result in the same consumer experience: declarative APIs available through <a href="/pr-preview/pr-80/overview/api-export-binding.html">APIExport/APIBinding</a>.</p><h2 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Path</th><th>Tool</th><th>What You Build</th><th>Sync Handled By</th><th>Best For</th></tr></thead><tbody><tr><td>1</td><td><a href="/pr-preview/pr-80/overview/api-syncagent.html">api-syncagent</a></td><td>Operator + deploy the sync agent</td><td>The agent (automatic)</td><td>Standard CRD-based services</td></tr><tr><td>2</td><td><a href="/pr-preview/pr-80/overview/multi-cluster-runtime.html">multi-cluster-runtime</a></td><td>Operator using mcr libraries</td><td>Your operator (built-in)</td><td>Non-CRD APIs, complex sync logic</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Important</p><p>Both paths require a Kubernetes operator that reconciles your service&#39;s resources. The paths differ in how synchronization between kcp and the service cluster is handled, not in whether you need an operator.</p></div><h2 id="path-1-api-syncagent" tabindex="-1">Path 1: api-syncagent <a class="header-anchor" href="#path-1-api-syncagent" aria-label="Permalink to &quot;Path 1: api-syncagent&quot;">​</a></h2><p>The <a href="/pr-preview/pr-80/overview/api-syncagent.html">api-syncagent</a> is the primary integration mechanism and the right choice for most providers. If you already have a Kubernetes operator with CRDs, the api-syncagent publishes those CRDs as <a href="/pr-preview/pr-80/overview/api-export-binding.html">APIExports</a> in kcp. It handles bidirectional sync (spec flows down from kcp, status flows back up), related resource synchronization, and schema evolution automatically.</p><p>You deploy the agent alongside your operator on the service cluster and create <code>PublishedResource</code> objects that declare which CRDs to expose. No custom controller code is needed for the sync layer -- the agent handles that entirely.</p><h2 id="path-2-multi-cluster-runtime" tabindex="-1">Path 2: multi-cluster-runtime <a class="header-anchor" href="#path-2-multi-cluster-runtime" aria-label="Permalink to &quot;Path 2: multi-cluster-runtime&quot;">​</a></h2><p><a href="/pr-preview/pr-80/overview/multi-cluster-runtime.html">multi-cluster-runtime</a> gives the provider full control by building sync logic directly into the operator. It is a Go library extending <code>controller-runtime</code>, so the added effort over writing a standard Kubernetes operator is minimal -- you use <code>mcr</code> packages instead of standard <code>controller-runtime</code> packages.</p><p>Use it when your service exposes non-CRD APIs (aggregated or custom API servers), when you need custom transformation logic during sync, or when the controller must coordinate state across multiple clusters. There is no separate sync agent to deploy and maintain -- your operator handles everything.</p>',11)),r("h2",p,[e[0]||(e[0]=a("Path 3: kube-bind ",-1)),h(o,{type:"warning",text:"WIP"}),e[1]||(e[1]=a()),e[2]||(e[2]=r("a",{class:"header-anchor",href:"#path-3-kube-bind","aria-label":'Permalink to "Path 3: kube-bind <Badge type="warning" text="WIP" />"'},"​",-1))]),e[4]||(e[4]=t('<p><a href="https://github.com/kube-bind/kube-bind" target="_blank" rel="noreferrer">kube-bind</a> will serve a dual role in Platform Mesh. First, it enables vanilla Kubernetes clusters to connect to the mesh as service providers, publishing their APIs Platform Mesh. Second, it allows consumers to extend their Platform Mesh control plane to their own workload clusters -- resources from the consumer&#39;s account appear on the workload cluster as if they were originally created there, enabling a fully local development and deployment experience. The <a href="/pr-preview/pr-80/scenarios/details.html">Scenarios</a> page illustrates how kube-bind fits into provider-to-consumer and provider-to-provider topologies. This integration path is currently under development.</p><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-80/overview/api-syncagent.html">api-syncagent</a> -- deep dive into the CRD-based sync agent</li><li><a href="/pr-preview/pr-80/overview/multi-cluster-runtime.html">multi-cluster-runtime</a> -- architecture and patterns for custom syncers</li><li><a href="/pr-preview/pr-80/overview/api-export-binding.html">APIExport &amp; APIBinding</a> -- the cross-workspace sharing mechanism all paths build on</li><li><a href="/pr-preview/pr-80/guides/provider-quick-start.html">Provider Quick Start</a> -- step-by-step guide to deploying your first service provider</li></ul>',3))])}const w=i(d,[["render",c]]);export{f as __pageData,w as default};
